/**
 * Abstract interface for container registry adapters
 *
 * Provides a common interface for interacting with different container
 * registry implementations (OpenShift ImageStream, generic OCI registries, etc.)
 *
 * Phase 1 (MVP): OpenShift ImageStream API only
 * Phase 2: Generic OCI registry support (Docker Registry HTTP API v2)
 */
export interface IRegistryAdapter {
  /**
   * List all backup images in a namespace
   *
   * @param namespace - Kubernetes namespace to query
   * @returns Promise resolving to array of backup images
   * @throws Error if registry query fails or times out
   */
  listBackupImages(namespace: string): Promise<IBackupImage[]>;

  /**
   * Get metadata for a specific backup image
   *
   * @param imageUrl - Full URL to the backup image (e.g., registry.io/namespace/name:tag)
   * @returns Promise resolving to image metadata
   * @throws Error if image not found or metadata cannot be retrieved
   */
  getImageMetadata(imageUrl: string): Promise<IImageMetadata>;

  /**
   * Validate that a backup image is accessible from the cluster
   *
   * Used for cross-cluster restore validation to ensure the image
   * can be pulled before attempting workspace creation.
   *
   * @param imageUrl - Full URL to the backup image
   * @returns Promise resolving to true if image is accessible, false otherwise
   */
  validateImageAccessibility(imageUrl: string): Promise<boolean>;
}
